create or replace function current_role() returns text language sql stable security definer as $$ select role from public.profiles where id = auth.uid() $$;
create or replace function is_admin_manager() returns boolean language sql stable security definer as $$ select coalesce(current_role() in ('ADMIN','MANAGER'), false) $$;
alter table profiles enable row level security; alter table customers enable row level security; alter table suppliers enable row level security; alter table shipments enable row level security; alter table containers enable row level security; alter table shipment_milestones enable row level security; alter table documents enable row level security; alter table carrier_rules enable row level security; alter table tracking_jobs enable row level security; alter table tracking_events enable row level security; alter table manual_reviews enable row level security; alter table alerts enable row level security; alter table settings enable row level security;
do $$ declare t text; begin foreach t in array array['profiles','customers','suppliers','shipments','containers','shipment_milestones','documents','carrier_rules','tracking_jobs','tracking_events','manual_reviews','alerts','settings'] loop execute format('create policy authenticated_read_%I on %I for select to authenticated using (true)', t, t); execute format('create policy admin_manager_all_%I on %I for all to authenticated using (is_admin_manager()) with check (is_admin_manager())', t, t); end loop; end $$;
create policy sales_update_assigned_shipments on shipments for update to authenticated using (current_role() = 'SALES' and sales_person = (select full_name from profiles where id = auth.uid())) with check (current_role() = 'SALES');
create policy purchase_update_import_shipments on shipments for update to authenticated using (current_role() = 'PURCHASE' and shipment_direction = 'IMPORT') with check (current_role() = 'PURCHASE');
create policy logistics_update_tracking_jobs on tracking_jobs for update to authenticated using (current_role() = 'LOGISTICS') with check (current_role() = 'LOGISTICS');
create policy logistics_update_milestones on shipment_milestones for update to authenticated using (current_role() = 'LOGISTICS') with check (current_role() = 'LOGISTICS');
create policy logistics_update_documents on documents for update to authenticated using (current_role() = 'LOGISTICS') with check (current_role() = 'LOGISTICS');
create policy logistics_insert_tracking_events on tracking_events for insert to authenticated with check (current_role() = 'LOGISTICS');
